// Parse and structure the order data
const body = $input.first().json.body || {};

// Basic Validation
const errors = [];
if (!body.shopDomain) errors.push('Missing shopDomain');
if (!body.items || !body.items.length) errors.push('Missing items');
if (!body.name) errors.push('Missing name');
if (!body.phone) errors.push('Missing phone');

if (errors.length > 0) {
  return [{ json: { valid: false, errors, body } }];
}

return [{
  json: {
    valid: true,
    shopDomain: body.shopDomain,
    orderData: body
  }
}];

// Find matching store credential
const stores = $input.all().map(i => i.json);
const requestData = $('Validate Input').first().json;
const shopDomain = requestData.shopDomain;

const store = stores.find(s => s.shopDomain === shopDomain || s.subdomain === shopDomain.replace('.myshopify.com', ''));

if (!store) {
  return [{ json: { found: false, error: 'Store not found in database' } }];
}

if (!store.accessToken) {
   return [{ json: { found: false, error: 'Store credentials missing (accessToken)' } }];
}

return [{ json: { found: true, store, orderData: requestData.orderData } }];

// Build Shopify Order GraphQL Mutation
const { store, orderData } = $input.first().json;

// 1. LINE ITEMS
let lineItems = [];
const qty = Number(orderData.quantity) || 1;

if (orderData.variantId) {
  let vid = String(orderData.variantId);
  if (!vid.startsWith('gid://')) vid = 'gid://shopify/ProductVariant/' + vid;
  lineItems.push({ variantId: vid, quantity: qty, requiresShipping: true });
} else {
  const items = orderData.items || [{ title: orderData.productTitle || 'Product', price: orderData.totalPrice, quantity: qty }];
  lineItems = items.map(item => ({
    title: item.title || 'Product',
    quantity: Number(item.quantity) || 1,
    originalUnitPrice: String(item.price || 0),
    requiresShipping: true
  }));
}

// 2. PHONE - STRICT E.164 VALIDATION
const rawPhone = (orderData.phone || '').trim();
const phoneDigits = rawPhone.replace(/\D/g, '');
let validPhone = undefined;

// Parse Algerian: 0555123456 -> +213555123456
let local = phoneDigits;
if (local.startsWith('00213')) local = local.substring(5);
else if (local.startsWith('213') && local.length > 10) local = local.substring(3);
else if (local.startsWith('0') && local.length === 10) local = local.substring(1);

if (local.length === 9 && /^[5-7]/.test(local)) {
    validPhone = '+213' + local;
} else if (rawPhone.startsWith('+') && phoneDigits.length >= 10 && phoneDigits.length <= 15) {
    validPhone = '+' + phoneDigits;
}
// If neither, validPhone stays undefined (will be OMITTED)

// 3. NAME & EMAIL
const rawName = (orderData.name || '').trim();
const parts = rawName.split(' ');
const firstName = parts[0] || 'Guest';
const lastName = parts.slice(1).join(' ') || '.';

let email = orderData.email;
if (!email || email.indexOf('@') < 0) {
    email = 'guest.' + (validPhone ? validPhone.replace('+','') : Date.now()) + '@generated.local';
}

// 4. ADDRESS (conditionally include phone)
const wilaya = (orderData.wilaya || '').replace(/^\d+\s*-\s*/, '');
const commune = orderData.commune || '';

const shippingAddress = {
  firstName,
  lastName,
  address1: orderData.address || commune || 'N/A',
  city: commune || wilaya || 'Algeria',
  province: wilaya,
  countryCode: 'DZ'
};
if (validPhone) shippingAddress.phone = validPhone;

// 5. SHIPPING
const shippingLines = [];
const shipCost = Number(orderData.shippingPrice) || 0;
if (shipCost > 0) {
  shippingLines.push({
    title: orderData.shippingType === 'desk' ? 'Stop Desk' : 'Home Delivery',
    priceSet: { shopMoney: { amount: String(shipCost), currencyCode: orderData.currency || 'DZD' } }
  });
}

// 6. TAGS & ATTRIBUTES
const tags = ['FinalForm', 'COD'];
if (orderData.shippingType) tags.push(orderData.shippingType);

const customAttributes = [];
const addAttr = (k, v) => { if (v) customAttributes.push({ key: k, value: String(v) }); };
addAttr('Wilaya', wilaya);
addAttr('Commune', commune);
addAttr('Original Phone', rawPhone);
addAttr('Validated Phone', validPhone || 'OMITTED');
addAttr('Form ID', orderData.formId);

// 7. ORDER INPUT (conditionally include phone)
const orderInput = {
  order: {
    lineItems,
    shippingLines,
    shippingAddress,
    billingAddress: shippingAddress,
    email,
    note: orderData.note || '',
    customAttributes,
    tags,
    financialStatus: 'PENDING'
  },
  options: { inventoryBehaviour: 'BYPASS' }
};
if (validPhone) orderInput.order.phone = validPhone;

// 8. QUERY
const query = `mutation orderCreate($order: OrderCreateOrderInput!, $options: OrderCreateOptionsInput) {
  orderCreate(order: $order, options: $options) {
    order { id name legacyResourceId }
    userErrors { field message }
  }
}`;

return [{ json: { graphqlQuery: query, graphqlVariables: orderInput, store, orderData, debug: { rawPhone, validPhone } } }];

// Parse Response
const input = $input.first().json;
const orderData = $('Build Mutation').first().json.orderData;

if (input.errors) {
   return [{ json: { success: false, errorType: 'GRAPHQL_SYSTEM', errors: input.errors.map(e => e.message) } }];
}

const result = input.data?.orderCreate;
if (!result) {
   return [{ json: { success: false, errorType: 'NO_DATA', errors: ['No data returned from Shopify'] } }];
}

if (result.userErrors && result.userErrors.length > 0) {
   return [{ json: { success: false, errorType: 'USER_ERROR', errors: result.userErrors.map(e => e.field.join('.') + ': ' + e.message) } }];
}

const order = result.order;
return [{
  json: {
    success: true,
    orderId: order.name,
    shopifyId: order.id,
    legacyId: order.legacyResourceId,
    message: 'Order created successfully'
  }
}];
